    def publish_batch(self, user_data_list, message_group_id=None):
        """
        Publish multiple user data messages in batch
        
        :param user_data_list: List of user data dictionaries
        :param message_group_id: Message group ID for FIFO queues
        :return: List of successful and failed message IDs
        """
        try:
            if not isinstance(user_data_list, list):
                raise ValueError("user_data_list must be a list")
            
            if len(user_data_list) > 10:
                raise ValueError("Batch size cannot exceed 10 messages")
            
            entries = []
            
            for idx, user_data in enumerate(user_data_list):
                data_to_send = user_data.copy()
                data_to_send['timestamp'] = datetime.utcnow().isoformat()
                data_to_send['message_version'] = '1.0'
                
                # Encrypt PII fields
                encrypted_data = self._encrypt_pii_fields(data_to_send)
                
                entry = {
                    'Id': str(idx),
                    'MessageBody': json.dumps(encrypted_data),
                    'MessageAttributes': {
                        'DataClassification': {
                            'StringValue': 'PII',
                            'DataType': 'String'
                        },
                        'EncryptionEnabled': {
                            'StringValue': str(bool(self.kms_key_id)),
                            'DataType': 'String'
                        }
                    }
                }
                
                if message_group_id:
                    entry['MessageGroupId'] = message_group_id
                    entry['MessageDeduplicationId'] = f"{message_group_id}-{idx}-{datetime.utcnow().timestamp()}"
                
                entries.append(entry)
            
            # Send batch
            response = self.sqs_client.send_message_batch(
                QueueUrl=self.queue_url,
                Entries=entries
            )
            
            successful = response.get('Successful', [])
            failed = response.get('Failed', [])
            
            print(f"Batch published: {len(successful)} successful, {len(failed)} failed")
            
            return {
                'successful': [msg['MessageId'] for msg in successful],
                'failed': failed
            }
            
        except ClientError as e:
            print(f"Error publishing batch to SQS: {e}")
            raise
        except Exception as e:
            print(f"Unexpected error: {e}")
            raise


